import React, { useState } from 'react';
import { useTranslation } from '../hooks/useTranslation';

const TrajetoriaProfissional = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState('webdev');

  const tabs = [
    { id: 'webdev', titleKey: 'webdev_tab_title', icon: 'bi-code-square' },
    { id: 'powerbi', titleKey: 'powerbi_tab_title', icon: 'bi-bar-chart-steps' },
    { id: 'react', titleKey: 'react_tab_title', icon: 'bi-bootstrap' },
    { id: 'database', titleKey: 'database_tab_title', icon: 'bi-database' },
    { id: 'logic', titleKey: 'logic_tab_title', icon: 'bi-diagram-3' },
    { id: 'ai', titleKey: 'ai_tab_title', icon: 'bi-cpu' },
    { id: 'java', titleKey: 'java_tab_title', icon: 'bi-filetype-java' },
  ];

  const experiences = [
    {
      titleKey: 'exp_1_title',
      roleKey: 'exp_1_role',
      periodKey: 'exp_1_period',
      textKey: 'exp_1_text',
      company: 'BootComp Tecnologia'
    },
    {
      titleKey: 'exp_2_title',
      roleKey: 'exp_2_role',
      periodKey: 'exp_2_period',
      textKey: 'exp_2_text',
      company: 'Prefeitura de Mogi das Cruzes'
    }
  ];

  return (
    <section id="jornada" className="jornada-section section">
      <div className="container">
        <div className="section-header text-center mb-5">
          <h2 data-translate="journey_title">{t('journey_title')}</h2>
        </div>

        {/* Timeline de Experiências */}
        <div className="timeline-container mb-5">
          {experiences.map((exp, index) => (
            <div key={index} className="timeline-item" data-aos="fade-up" data-aos-delay={index * 100}>
              <div className="timeline-badge">
                <i className="bi bi-briefcase-fill"></i>
              </div>
              <div className="timeline-content">
                <h3>{exp.company}</h3>
                <h4 data-translate={exp.roleKey}>{t(exp.roleKey)}</h4>
                <p className="timeline-period" data-translate={exp.periodKey}>{t(exp.periodKey)}</p>
                <p data-translate={exp.textKey}>{t(exp.textKey)}</p>
              </div>
            </div>
          ))}
        </div>

        {/* Tabs de Habilidades Técnicas */}
        <div className="skills-tabs-container">
          <div className="skills-tabs-nav">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                className={`skills-tab-btn ${activeTab === tab.id ? 'active' : ''}`}
                onClick={() => setActiveTab(tab.id)}
              >
                <i className={`bi ${tab.icon} me-2`}></i>
                <span data-translate={tab.titleKey}>{t(tab.titleKey)}</span>
              </button>
            ))}
          </div>

          <div className="skills-tab-content">
            {/* Conteúdo de cada tab - adicione conforme necessário */}
            {activeTab === 'webdev' && (
              <div className="skills-grid">
                <div className="skill-item">HTML/CSS</div>
                <div className="skill-item">JavaScript</div>
                <div className="skill-item">TypeScript</div>
                <div className="skill-item">Angular</div>
                <div className="skill-item">Spring Boot</div>
              </div>
            )}
            {activeTab === 'powerbi' && (
              <div className="skills-grid">
                <div className="skill-item">Power BI Desktop</div>
                <div className="skill-item">DAX</div>
                <div className="skill-item">Power Query</div>
                <div className="skill-item">Dashboard Design</div>
              </div>
            )}
            {/* Continue para as outras tabs */}
          </div>
        </div>
      </div>

      <style jsx>{`
        .timeline-container {
          position: relative;
          padding: 20px 0;
        }

        .timeline-item {
          display: flex;
          gap: 20px;
          margin-bottom: 40px;
          position: relative;
        }

        .timeline-badge {
          flex-shrink: 0;
          width: 50px;
          height: 50px;
          background: var(--surface-1);
          border: 1px solid var(--hairline);
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          color: var(--accent-color);
          font-size: 1.2rem;
          z-index: 1;
        }

        .timeline-content {
          flex: 1;
          background: var(--surface-1);
          border: 1px solid var(--hairline);
          border-radius: 16px;
          padding: 20px 24px;
          transition: all 0.3s ease;
        }

        .timeline-content:hover {
          transform: translateY(-4px);
          border-color: var(--green-soft);
          box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
        }

        .timeline-content h3 {
          font-size: 1.25rem;
          font-weight: 600;
          color: var(--fg);
          margin-bottom: 4px;
        }

        .timeline-content h4 {
          font-size: 1rem;
          font-weight: 500;
          color: var(--accent-color);
          margin-bottom: 6px;
        }

        .timeline-period {
          font-size: 0.85rem;
          color: var(--fg-muted);
          margin-bottom: 12px;
        }

        .timeline-content p:last-child {
          color: var(--fg-muted);
          line-height: 1.6;
        }

        /* Skills Tabs */
        .skills-tabs-nav {
          display: flex;
          flex-wrap: wrap;
          gap: 12px;
          margin-bottom: 30px;
          justify-content: center;
        }

        .skills-tab-btn {
          background: var(--surface-1);
          border: 1px solid var(--hairline);
          padding: 10px 20px;
          border-radius: 40px;
          font-size: 14px;
          font-weight: 500;
          color: var(--fg-muted);
          cursor: pointer;
          transition: all 0.3s ease;
          display: inline-flex;
          align-items: center;
        }

        .skills-tab-btn i {
          font-size: 16px;
        }

        .skills-tab-btn:hover {
          background: var(--surface-2);
          border-color: var(--green-soft);
          color: var(--green-soft);
          transform: translateY(-2px);
        }

        .skills-tab-btn.active {
          background: var(--green-soft);
          border-color: var(--green-soft);
          color: var(--ink);
        }

        .skills-tab-content {
          background: var(--surface-1);
          border: 1px solid var(--hairline);
          border-radius: 20px;
          padding: 30px;
        }

        .skills-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
          gap: 15px;
        }

        .skill-item {
          background: var(--surface-2);
          border: 1px solid var(--hairline);
          border-radius: 12px;
          padding: 12px 16px;
          text-align: center;
          font-size: 14px;
          font-weight: 500;
          color: var(--fg-muted);
          transition: all 0.3s ease;
          cursor: pointer;
        }

        .skill-item:hover {
          transform: translateY(-2px);
          border-color: var(--green-soft);
          color: var(--green-soft);
        }

        @media (max-width: 768px) {
          .timeline-item {
            flex-direction: column;
            gap: 12px;
          }
          
          .timeline-badge {
            width: 40px;
            height: 40px;
            font-size: 1rem;
          }
          
          .timeline-content {
            padding: 16px;
          }
          
          .skills-tabs-nav {
            gap: 8px;
          }
          
          .skills-tab-btn {
            padding: 6px 14px;
            font-size: 12px;
          }
          
          .skills-grid {
            grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
            gap: 10px;
          }
        }
      `}</style>
    </section>
  );
};

export default TrajetoriaProfissional;
